<template><main class="login-screen"><section class="login-intro" aria-labelledby="login-title"><img src="../assets/TokenSea_logo.png" alt="TokenSea"/><div class="login-rule"></div><p>统一管理模型供应商、平台模型、访问密钥、路由与用量归因。</p></section><section class="login-panel"><div class="eyebrow">安全登录</div><h1 id="login-title">进入运营控制台</h1><p>使用管理员分配的账号登录。</p><div v-if="error" class="inline-alert danger" role="alert">{{ error }}</div><a-form layout="vertical" @submit.prevent="login"><a-form-item label="账号"><a-input v-model:value="username" autocomplete="username" autofocus placeholder="请输入账号"/></a-form-item><a-form-item label="密码"><a-input-password v-model:value="password" autocomplete="current-password" placeholder="请输入密码"/></a-form-item><a-button type="primary" html-type="submit" block :loading="loading">登录</a-button></a-form></section></main></template>
<script setup lang="ts">import{ref}from'vue';import{useRoute,useRouter}from'vue-router';import{api,errorMessage,isAdmin}from'../api/client';const router=useRouter(),route=useRoute(),username=ref(''),password=ref(''),loading=ref(false),error=ref('');async function login(){if(!username.value||!password.value){error.value='请输入账号和密码';return}loading.value=true;error.value='';try{const response=await api.post('/api/auth/login',{username:username.value,password:password.value});const token=response.data?.data?.token;if(!token)throw new Error('登录响应缺少访问令牌');localStorage.setItem('tokensea_token',token);const redirect=typeof route.query.redirect==='string'?route.query.redirect:(isAdmin()?'/dashboard':'/workspace');await router.replace(redirect)}catch(e){error.value=errorMessage(e)}finally{loading.value=false}}</script>
